// Solution
var solve = function(documents) {
    var pipeline = [
        {
            $group: {
                _id: "$field",
                sum: { $sum: "$numericField" },
                count: { $sum: { $cond: [{ $ne: ['$b', null] }, 1, 0] } }
            }
        },
        {
            $project: {
                _id: 1,
                sum: 1,
                count: 1
            }
        }
    ];
    return pipeline;
};

